// src/services/experiences.js
import api from './api';
const API_URL = '/experiences/'; // الـ base URL غالباً مضاف في إعدادات axios

export const experiencesService = {
  getAll: (params = {}) => api.get(API_URL, { params }),

  getById: (id) => api.get(`${API_URL}${id}/`),

  // الشراء: سيوجه لـ /api/experiences/{id}/buy/
  buy: (experienceId) => api.post(`${API_URL}${experienceId}/buy/`),

  // المشتريات: سيوجه لـ /api/experiences/my_purchases/
  my_purchases: () => api.get(`${API_URL}my_purchases/`),

  // الإضافة والتعديل: كلها على نفس الرابط API_URL
  create: (data) => api.post(API_URL, data, {
    headers: { 'Content-Type': 'multipart/form-data' },
  }),

  update: (id, data) => api.patch(`${API_URL}${id}/`, data),

  toggleStatus: (id) => api.patch(`${API_URL}${id}/toggle_status/`),
};
